import os
from datetime import datetime, timedelta
from functools import wraps
from flask import Flask, request, jsonify
import jwt
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# Secure configuration
SECRET_KEY = os.environ.get('JWT_SECRET_KEY') or os.urandom(32).hex()
ALGORITHM = 'HS256'
TOKEN_EXPIRATION_HOURS = 1
REFRESH_TOKEN_EXPIRATION_DAYS = 7

# In-memory user storage (replace with database in production)
users_db = {}

# Token blacklist for logout functionality
token_blacklist = set()


def create_access_token(user_id):
    """Create a secure JWT access token with proper claims"""
    payload = {
        'user_id': user_id,
        'exp': datetime.utcnow() + timedelta(hours=TOKEN_EXPIRATION_HOURS),
        'iat': datetime.utcnow(),
        'nbf': datetime.utcnow(),
        'type': 'access'
    }
    return jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)


def create_refresh_token(user_id):
    """Create a secure JWT refresh token"""
    payload = {
        'user_id': user_id,
        'exp': datetime.utcnow() + timedelta(days=REFRESH_TOKEN_EXPIRATION_DAYS),
        'iat': datetime.utcnow(),
        'nbf': datetime.utcnow(),
        'type': 'refresh'
    }
    return jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)


def verify_token(token, token_type='access'):
    """Verify JWT token with strict validation"""
    try:
        # Strict verification with explicit algorithm
        payload = jwt.decode(
            token,
            SECRET_KEY,
            algorithms=[ALGORITHM],
            options={
                'verify_signature': True,
                'verify_exp': True,
                'verify_nbf': True,
                'verify_iat': True,
                'require_exp': True,
                'require_iat': True,
                'require_nbf': True
            }
        )
        
        # Verify token type
        if payload.get('type') != token_type:
            return None
        
        # Check if token is blacklisted
        if token in token_blacklist:
            return None
        
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None
    except Exception:
        return None


def token_required(f):
    """Decorator to protect routes with JWT authentication"""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None
        
        # Get token from Authorization header
        auth_header = request.headers.get('Authorization')
        if auth_header and auth_header.startswith('Bearer '):
            token = auth_header.split(' ')[1]
        
        if not token:
            return jsonify({'error': 'Token is missing'}), 401
        
        # Verify token
        payload = verify_token(token, token_type='access')
        if not payload:
            return jsonify({'error': 'Token is invalid or expired'}), 401
        
        # Check if user exists
        user_id = payload.get('user_id')
        if user_id not in users_db:
            return jsonify({'error': 'User not found'}), 401
        
        # Pass user_id to the route
        return f(user_id=user_id, *args, **kwargs)
    
    return decorated


@app.route('/register', methods=['POST'])
def register():
    """Register a new user"""
    data = request.get_json()
    
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'error': 'Username and password required'}), 400
    
    username = data['username']
    password = data['password']
    
    # Check if user already exists
    if username in users_db:
        return jsonify({'error': 'User already exists'}), 400
    
    # Validate password strength
    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400
    
    # Store user with hashed password
    users_db[username] = {
        'password_hash': generate_password_hash(password, method='pbkdf2:sha256'),
        'created_at': datetime.utcnow().isoformat()
    }
    
    return jsonify({'message': 'User registered successfully'}), 201


@app.route('/login', methods=['POST'])
def login():
    """Authenticate user and return JWT tokens"""
    data = request.get_json()
    
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'error': 'Username and password required'}), 400
    
    username = data['username']
    password = data['password']
    
    # Check if user exists
    if username not in users_db:
        return jsonify({'error': 'Invalid credentials'}), 401
    
    # Verify password
    user = users_db[username]
    if not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid credentials'}), 401
    
    # Create tokens
    access_token = create_access_token(username)
    refresh_token = create_refresh_token(username)
    
    return jsonify({
        'access_token': access_token,
        'refresh_token': refresh_token,
        'token_type': 'Bearer',
        'expires_in': TOKEN_EXPIRATION_HOURS * 3600
    }), 200


@app.route('/refresh', methods=['POST'])
def refresh():
    """Refresh access token using refresh token"""
    data = request.get_json()
    
    if not data or not data.get('refresh_token'):
        return jsonify({'error': 'Refresh token required'}), 400
    
    refresh_token = data['refresh_token']
    
    # Verify refresh token
    payload = verify_token(refresh_token, token_type='refresh')
    if not payload:
        return jsonify({'error': 'Invalid or expired refresh token'}), 401
    
    user_id = payload.get('user_id')
    
    # Check if user still exists
    if user_id not in users_db:
        return jsonify({'error': 'User not found'}), 401
    
    # Create new access token
    access_token = create_access_token(user_id)
    
    return jsonify({
        'access_token': access_token,
        'token_type': 'Bearer',
        'expires_in': TOKEN_EXPIRATION_HOURS * 3600
    }), 200


@app.route('/logout', methods=['POST'])
@token_required
def logout(user_id):
    """Logout user by blacklisting the token"""
    auth_header = request.headers.get('Authorization')
    token = auth_header.split(' ')[1]
    
    # Add token to blacklist
    token_blacklist.add(token)
    
    return jsonify({'message': 'Logged out successfully'}), 200


@app.route('/protected', methods=['GET'])
@token_required
def protected(user_id):
    """Example protected route"""
    return jsonify({
        'message': 'This is a protected resource',
        'user_id': user_id,
        'timestamp': datetime.utcnow().isoformat()
    }), 200


@app.route('/profile', methods=['GET'])
@token_required
def profile(user_id):
    """Get user profile"""
    user = users_db.get(user_id)
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    return jsonify({
        'user_id': user_id,
        'created_at': user['created_at']
    }), 200


if __name__ == '__main__':
    app.run(debug=False)